    }()

    private let insecureLegacyButton: UIButton = {
        let button = UIButton(type: .system)
        button.translatesAutoresizingMaskIntoConstraints = false
        button.setTitle("Call Insecure Legacy (legacy.internal)", for: .normal)
        button.backgroundColor = .systemRed
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 8
        return button
    }()

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .white
        setupUI()
    }

    private func setupUI() {
        let stackView = UIStackView(arrangedSubviews: [secureApiButton, insecureLegacyButton])
        stackView.translatesAutoresizingMaskIntoConstraints = false
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.distribution = .fillEqually

        view.addSubview(resultLabel)
        view.addSubview(stackView)

        NSLayoutConstraint.activate([
            resultLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            resultLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            resultLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            resultLabel.heightAnchor.constraint(equalToConstant: 200),

            stackView.topAnchor.constraint(equalTo: resultLabel.bottomAnchor, constant: 40),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 40),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -40),
            stackView.heightAnchor.constraint(equalToConstant: 120)
        ])

        secureApiButton.addTarget(self, action: #selector(callSecureApi), for: .touchUpInside)
        insecureLegacyButton.addTarget(self, action: #selector(callInsecureLegacy), for: .touchUpInside)
    }

    @objc private func callSecureApi() {
        let urlString = "https://api.example.com/data" // Replace with your actual secure API endpoint
        makeRequest(urlString: urlString)
    }

    @objc private func callInsecureLegacy() {
        let urlString = "http://legacy.internal/status" // Replace with your actual legacy internal endpoint
        makeRequest(urlString: urlString)
    }

    private func makeRequest(urlString: String) {
        guard let url = URL(string: urlString) else {
            DispatchQueue.main.async {
                self.resultLabel.text = "Error: Invalid URL"
            }
            return
        }

        DispatchQueue.main.async {
            self.resultLabel.text = "Making request to: \(urlString)..."
        }

        let task = URLSession.shared.dataTask(with: url) { [weak self] data, response, error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.resultLabel.text = "Request failed for \(urlString):\n\(error.localizedDescription)"
                    print("Error for \(urlString): \(error)")
                    return
                }

                guard let httpResponse = response as? HTTPURLResponse else {
                    self?.resultLabel.text = "Request failed for \(urlString):\nNo HTTP response"
                    return
                }

                if httpResponse.statusCode == 200 {
                    if let data = data, let dataString = String(data: data, encoding: .utf8) {
                        self?.resultLabel.text = "Success from \(urlString) (Status: \(httpResponse.statusCode)):\n\(dataString.prefix(200))..."
                    } else {
                        self?.resultLabel.text = "Success from \(urlString) (Status: \(httpResponse.statusCode))\nNo data received or data not UTF-8."
                    }
                } else {
                    self?.resultLabel.text = "Request failed for \(urlString) (Status: \(httpResponse.statusCode))"
                }
            }
        }
        task.resume()
    }
}

